...

# Terminating

xlog("L_INFO", "Detected: this transaction is on the \"Term\" S-CSCF");

if (uri == myself || uri =~ "tel:.*") {
  if (!term_impu_registered("location")) {
    xlog("L_INFO", "user not registered -> try unreg services");
    $var(ret) = analyse_domain_ruri();
    if ($var(ret) < 0) {
      $var(ret) = (uri_param("user","gsmr") && ($rU=~"^[0-9]+$"));
      if ($var(ret)) {
        $var(ret) = analyse_eirene_ruri();
      } else {
        $var(ret)=(uri_param("user","phone") && ($rU =~ "^\+[0-9]+$")));
        if ($var(ret)) {
          $var(ret) = analyse_e164_ruri();
        } else {
          $var(ret) = analyse_dpsi_ruri();
        }
      }
    }
    if ($var(ret) < 0){
      if ($var(ret) == -2) {
        xlog("L_ERR", "found RDN service/DPSI, could not set AVP");
        sl_send_reply("500", "Server Internal Error - Cannot set AVP");
        exit;
      }
      xlog("L_INFO", "did not find RDN Service/DPSI -> try UNREG SAR");
      assign_server_unreg("UNREG_SAR_REPLY", "location", "term");
      exit;
    }
    else {
      if (!prepare_term_unreg("location")) {
        xlog("L_ERR", "found RDN service/DPSI, cannot prepare DB for sending");
        sl_send_reply("500", "Server Internal Error - Cannot prepare sending service");
        exit;
      }
      if ($var(ret) == 2) {
        xlog("L_INFO", "RDN Service has hardcoded RURI, but w/o user part");
        route(fwd);
        exit;
      }
      xlog("L_INFO", "could prepare unreg terminating service -> continue");
    }
  }
  else {
    xlog("L_INFO", "user is registered at this S-CSCF, continue");
  }
} else {
  xlog("L_INFO", "Terminating S-CSCF detects: this request is not for me");
  sl_send_reply("403","Forbidden - Domain not served");
  exit();
}
route(term);
break;
